using System.ComponentModel;
using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Agents.AI;
using OpenAI;

var builder = Host.CreateApplicationBuilder(args);

var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set AI:ApiKey in configuration or OPENAI_API_KEY environment variable.");

const string modelId = "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(b => b
    .UseOpenAIChatClient(modelId, new OpenAIClient(apiKey)));

builder.Services.AddSingleton<ResearchTools>();

var host = builder.Build();

var chatClient = host.Services.GetRequiredService<IChatClient>();
var tools = host.Services.GetRequiredService<ResearchTools>();

var agent = new ChatClientAgent(chatClient, "ResearchAgent")
{
    Instructions = """
        You are a research agent. When given a topic:
        1. Search the web for relevant information (perform multiple searches to cover different angles).
        2. Take notes on important findings using the note-taking tool.
        3. After gathering enough information, produce a final summary of your findings.
        Always cite which searches led to which findings.
        """,
};

var topic = args.Length > 0
    ? string.Join(' ', args)
    : "the impact of large language models on software development in 2025";

Console.WriteLine($"🔍 Researching: {topic}\n");

var options = new AgentInvokeOptions
{
    MaximumIterations = 10,
    ModelOptions = new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 2048,
        Tools = [.. AIFunctionFactory.Create(tools)],
    },
};

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and provide a comprehensive summary: {topic}"),
};

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (!string.IsNullOrEmpty(message.Text))
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine("\n\n📝 Notes collected during research:");
foreach (var note in tools.GetNotes())
{
    Console.WriteLine($"  • {note}");
}

/// <summary>Tools available to the research agent.</summary>
public sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _http = new();

    [Description("Searches the web for information on a query. Returns search result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  [Tool] Searching: \"{query}\"");

        try
        {
            // Uses a public search API (DuckDuckGo instant answer) for demonstration
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var response = await _http.GetStringAsync(url);

            // Parse a simplified result
            using var doc = System.Text.Json.JsonDocument.Parse(response);
            var root = doc.RootElement;

            var results = new List<string>();

            if (root.TryGetProperty("AbstractText", out var abs) && abs.GetString() is { Length: > 0 } abstractText)
                results.Add($"Summary: {abstractText}");

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) && text.GetString() is { Length: > 0 } t)
                        results.Add($"- {t}");
                }
            }

            return results.Count > 0
                ? string.Join('\n', results)
                : $"No detailed results found for '{query}'. Try a more specific query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try rephrasing the query.";
        }
    }

    [Description("Saves a research note for later reference. Use this to record key findings.")]
    public string TakeNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  [Tool] Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    public IReadOnlyList<string> GetNotes() => _notes;
}

