/// <summary>Tools available to the research agent.</summary>
public sealed class ResearchTools
{
    private readonly List<string> _notes = [];
    private readonly HttpClient _http = new();

    [Description("Searches the web for information on a query. Returns search result snippets.")]
    public async Task<string> SearchWeb(
        [Description("The search query string")] string query)
    {
        Console.WriteLine($"  [Tool] Searching: \"{query}\"");

        try
        {
            // Uses a public search API (DuckDuckGo instant answer) for demonstration
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
            var response = await _http.GetStringAsync(url);

            // Parse a simplified result
            using var doc = System.Text.Json.JsonDocument.Parse(response);
            var root = doc.RootElement;

            var results = new List<string>();

            if (root.TryGetProperty("AbstractText", out var abs) && abs.GetString() is { Length: > 0 } abstractText)
                results.Add($"Summary: {abstractText}");

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    if (topic.TryGetProperty("Text", out var text) && text.GetString() is { Length: > 0 } t)
                        results.Add($"- {t}");
                }
            }

            return results.Count > 0
                ? string.Join('\n', results)
                : $"No detailed results found for '{query}'. Try a more specific query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try rephrasing the query.";
        }
    }

    [Description("Saves a research note for later reference. Use this to record key findings.")]
    public string TakeNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        Console.WriteLine($"  [Tool] Note saved ({_notes.Count} total)");
        return $"Note saved. You now have {_notes.Count} note(s).";
    }

    public IReadOnlyList<string> GetNotes() => _notes;
}

